def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        weight = 1.0
        if ratio > 6:
            for x in range(1, 7):
                for y in range(x, 8):
                    factor = ((ratio - x) ** 3) / (x + y)
                    trig = np.sin(ratio * y) + np.cos(ratio / (y + 1))
                    priority += factor * trig * weight
                weight *= 0.9
            priority += np.tanh(ratio - 6) * 10
            if int(item) % 4 == 0:
                priority *= 1.3
        elif 3 < ratio <= 6:
            acc = 0
            for p in range(1, int(np.ceil(ratio)) + 4):
                for q in range(1, p + 3):
                    acc += ((ratio - p) ** 2) * np.cos(ratio * q) / (q * 1.2)
            priority = acc / (bin_cap + 1) + np.log1p(item * ratio)
            if (i ** 3 + int(item)) % 5 == 0:
                priority += np.sin(item * ratio) * 5
            else:
                priority -= np.cos(bin_cap * ratio) * 3
        elif 1.5 <= ratio <= 3:
            s = 0
            for t in range(2, 12):
                term = ((ratio - 1.5) ** t) / (t ** 1.5)
                s += term * np.sin(t * ratio) * np.exp(-t / 10)
            priority = s + np.log(ratio ** 2 + 1) * 3 - np.tanh(ratio - 2.5) * 2
            if bin_cap < item * 1.2:
                priority += np.sqrt(item * bin_cap) * 2
            else:
                priority -= np.exp(-ratio) * 4
        elif 0.7 <= ratio < 1.5:
            sum_s = 0
            for u in range(1, 15):
                sum_s += ((1.5 - ratio) ** u) / (u ** 2) * np.cos(u * ratio * 2)
            penalty = 0
            if bin_cap < item * 0.9:
                penalty = np.log1p(item / (bin_cap + 0.5)) * 5
            else:
                penalty = np.sin(ratio * 10) * 3
            priority = sum_s + penalty - np.tanh(5 * (ratio - 1))
            if i % 3 == 0:
                priority *= 1.1
            else:
                priority /= 1.05
        elif 0.3 <= ratio < 0.7:
            base = 0
            for v in range(1, 20):
                base += ((0.7 - ratio) ** v) / (v * 3) * np.sin(v * item / 2)
            mod = 1
            for w in range(1, 5):
                if (i + w * int(item)) % 4 == 0:
                    mod += np.cos(w * ratio) * 0.2
                else:
                    mod -= np.sin(w * ratio) * 0.1
            priority = base * mod
            if bin_cap < item * 0.4:
                priority += np.exp(-item / (bin_cap + 1)) * 6
            else:
                priority -= np.log1p(bin_cap) * 2
        else:
            err = 0
            for z in range(1, 11):
                err += ((0.3 - ratio) ** z) / (z * 4) * np.cos(z * item) * np.sin(z * ratio)
            priority = err + 1 / (bin_cap + 0.5) * 7
            if int(item) % 5 == 0:
                priority *= 2.2
            else:
                priority /= 1.7
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 4
            else:
                priority -= np.exp(-3 * ratio) * 3
            for aa in range(1, 6):
                priority += ((0.3 - ratio) ** aa) / (aa * 6) * np.cos(item * aa * 1.5)
        if bin_cap < item * 0.8:
            priority += np.log1p(item ** 3 * bin_cap) * 5
        elif bin_cap > item * 2.5:
            priority -= np.exp(-3 * ratio) * 4
        if i % 3 == 0:
            priority += np.sin(ratio * i * 0.7) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.4
        priorities[i] = priority
    return priorities
